    __easting = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'easting'), 'easting', '__httpwww_witsml_orgschemas131_cs_location_httpwww_witsml_orgschemas131easting', False, pyxb.utils.utility.Location('cs_location.xsd', 57, 5), )

    
