cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'latitude'), planeAngleMeasure, scope=cs_location, documentation='The latitude with north being positive.', location=pyxb.utils.utility.Location('cs_location.xsd', 45, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'longitude'), planeAngleMeasure, scope=cs_location, documentation='The longitude with east being positive.', location=pyxb.utils.utility.Location('cs_location.xsd', 50, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'easting'), lengthMeasure, scope=cs_location, documentation='The projected coordinate with east being positive. \n\t\t\t\t\t\t\tThis is the most common type of projected coordinates. \n\t\t\t\t\t\t\tUTM coordinates are expressed in Easting and Northing.', location=pyxb.utils.utility.Location('cs_location.xsd', 57, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'northing'), lengthMeasure, scope=cs_location, documentation='The projected coordinate with north being positive. \n\t\t\t\t\t\t\tThis is the most common type of projected coordinates. \n\t\t\t\t\t\t\tUTM coordinates are expressed in Easting and Northing.', location=pyxb.utils.utility.Location('cs_location.xsd', 64, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'westing'), lengthMeasure, scope=cs_location, documentation='The projected coordinate with west being positive. \n\t\t\t\t\t\t\tThe positive directions are reversed from the usual Easting and Northing values. \n\t\t\t\t\t\t\tThese values are generally located in the southern hemisphere, \n\t\t\t\t\t\t\tmost notably in South Africa and Australia.', location=pyxb.utils.utility.Location('cs_location.xsd', 73, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'southing'), lengthMeasure, scope=cs_location, documentation='The projected coordinate with south being positive. \n\t\t\t\t\t\t\tThe positive directions are reversed from the usual Easting and Northing values. \n\t\t\t\t\t\t\tThese values are generally located in the southern hemisphere, \n\t\t\t\t\t\t\tmost notably in South Africa and Australia.', location=pyxb.utils.utility.Location('cs_location.xsd', 81, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'projectedX'), lengthMeasure, scope=cs_location, documentation='The projected X coordinate with the positive direction unknown.\n\t\t\t\t\t\t\tProjectedX and ProjectedY are used when it is not \n\t\t\t\t\t\t\tknown what the meaning of the coordinates is. If the meaning is known, \n\t\t\t\t\t\t\tthe Easting/Northing or Westing/Southing should be used. Use of this pair \n\t\t\t\t\t\t\timplies a lack of knowledge on the part of the sender.', location=pyxb.utils.utility.Location('cs_location.xsd', 91, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'projectedY'), lengthMeasure, scope=cs_location, documentation='The projected Y coordinate with the positive direction unknown.\n\t\t\t\t\t\t\tProjectedX and ProjectedY are used when it is not \n\t\t\t\t\t\t\tknown what the meaning of the coordinates is. If the meaning is known, \n\t\t\t\t\t\t\tthe Easting/Northing or Westing/Southing should be used. Use of this pair \n\t\t\t\t\t\t\timplies a lack of knowledge on the part of the sender.', location=pyxb.utils.utility.Location('cs_location.xsd', 100, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'localX'), lengthMeasure, scope=cs_location, documentation='The local (engineering) X coordinate. \n\t\t\t\t\t\t\tThe CRS will define the orientation of the axis.', location=pyxb.utils.utility.Location('cs_location.xsd', 111, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'localY'), lengthMeasure, scope=cs_location, documentation='The local (engineering) Y coordinate. \n\t\t\t\t\t\t\tThe CRS will define the orientation of the axis.', location=pyxb.utils.utility.Location('cs_location.xsd', 117, 5)))

cs_location._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'original'), logicalBoolean, scope=cs_location, documentation='Flag indicating (if "true" or "1") that this pair of values was \n\t\t\t\t\tthe original data given for the location. If the pair of values was \n\t\t\t\t\tcalculated from an original pair of values, this flag should be "false" (or "0"), \n\t\t\t\t\tor not present.', location=pyxb.utils.utility.Location('cs_location.xsd', 125, 3)))

